TRACK_LENGTH = len(TRACK)

@module.event
async def on_ready():
    b1.value(0)
    b2.value(0)
    b3.value(0)

@module.task()
async def buzz():
    if time.ticks_diff(module.g["next"], time.ticks_ms()) <= 0:
        module.g["next"] = (time.ticks_ms() + 125)
        if not len(TRACK): 
            b1.value(0)
            b2.value(0)
            b3.value(0)
            return

        notes = TRACK.pop(0)

        if module.g["started"] is None:
            print("Now playing: Final Duet - Omori OST")
            module.g["started"] = time.ticks_ms()

        current_time = round(time.ticks_diff(time.ticks_ms(), module.g["started"])/1000)
        m, s = divmod(current_time, 60)
        msg = f"{m}:{s:0>2}"
        percentage_done = round((1-(len(TRACK) / TRACK_LENGTH))*100)
        if module.g["last_percentage"] != percentage_done: msg += f" {percentage_done}%"
        module.g["last_percentage"] = percentage_done
        print(msg)

        if not isinstance(notes, tuple):
            notes = (notes,)
        notes = list(notes)
        while len(notes) < 3:
            notes.append("P")
        
        for note,b in zip(notes,[b1,b2,b3]):
            if note == "P":
                b.value(0)
                return
                
            u16 = TONES[note]

            b.value(1000)
            b.freq(u16)

try:
    module.run()
except KeyboardInterrupt:
    b1.value(0)
    b2.value(0)
    b3.value(0)